mapper.select:
SELECT hc.*, sa1.name AS communityProvinceName, sa2.name AS communityCityName, sa3.name AS communityTownName FROM hjy_community hc LEFT JOIN sys_area sa1 ON hc.community_province_code = sa1.`code` LEFT JOIN sys_area sa2 ON hc.community_city_code = sa2.`code` LEFT JOIN sys_area sa3 ON hc.community_town_code = sa3.`code`
AND hc.community_name LIKE CONCAT('%', #{community.communityName}, '%')
AND hc.community_code = #{community.communityCode}
